// packages/database/src/db/schema/part.ts
// Drizzle table: part (generated by scripts/split-schema.ts)

import { pgTable, uniqueIndex, text, timestamp, integer, type AnyPgColumn } from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { User } from './user'
import { Organization } from './organization'

/** Drizzle table for part */
export const Part = pgTable(
  'Part',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    title: text().notNull(),
    description: text(),
    sku: text().notNull(),
    hsCode: text(),
    category: text(),
    shopifyProductLinkId: text(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    cost: integer(),
    createdById: text().references((): AnyPgColumn => User.id, { onUpdate: 'cascade' }),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
  },
  (table) => [uniqueIndex('Part_sku_key').using('btree', table.sku.asc().nullsLast())]
)
